// Up to 4 rounds: each round Gemini either calls a tool OR writes
// its final answer. If it calls a tool, we run it and go again.
for (let round = 0; round < MAX_TOOL_ROUNDS; round++) {
  const stream = await client.models.generateContentStream({
    model: 'gemini-2.5-flash',
    contents,             // full conversation history
    config: {
      systemInstruction: SYSTEM_PROMPT,
      maxOutputTokens: 1500,
      tools: [{ functionDeclarations: TOOL_DECLARATIONS }],
    },
  });

  const calls = [];
  for await (const chunk of stream) {
    if (chunk.text) {
      answer += chunk.text;
      onEvent({ type: 'delta', text: chunk.text }); // stream to browser
    }
    for (const fc of chunk.functionCalls ?? []) {
      calls.push({ name: fc.name, args: fc.args }); // collect tool calls
    }
  }

  if (calls.length === 0) break; // no tools called → done

  // Run every tool, emit cards to browser, collect results for Gemini
  for (const call of calls) {
    const { result, modelPayload } = await runTool(call.name, call.args);
    if (result) onEvent({ type: 'tool', result }); // lab/test cards appear
    contents.push({ role: 'user',
      parts: [{ functionResponse: { name: call.name,
                                    response: modelPayload } }] });
  }
}
